INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (10.85, "エリコ", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 100, "2030/12/17 14:59:59", "訓練成功、おめでとうございます\n褒めるべき時にはしっかり褒めるのも\n教官の務めですものね。それとも、\n罵られる方が好みですか？　クスクス", 7, 100);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (11.15, "エリコ", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 101, "2030/12/17 14:59:59", "厳しい訓練も、終わってみれば\n短く感じるものですわね。\n正直、私は暴れ足りないくらい…\nいえ、何でもありませんわ。クスクス", 2, 101);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (6.4, "エリコ", 10142, 7, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 102, "2030/12/17 14:59:59", "行く手を阻む忌々しい邪魔者を\n蹴散らして、見事ゴールイン…！\nまるで私とあのおかたの人生を\n象徴するような道のりでした…", 5, 102);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (0.0, "エリコ", 10142, 3, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 103, "2030/12/17 14:59:59", "まったくもって不甲斐ない結果です\nしかし、挽回の機会はまだありますわ\n次はゴミ虫の地位から脱却できるよう\n死力を尽くしなさい。いいですね？", 3, 103);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (2.43, "エリコ", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 104, "2030/12/17 14:59:59", "クスクス…ああご心配なさらず\nなんとも情けない成績を残す輩には\nどんな罰が相応しいか、考えている\nだけですので…クスクスクス", 8, 104);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (9.08, "エリコ", 10142, 4, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 105, "2030/12/17 14:59:59", "私が教官として認められなければ、\nあのおかたを失望させてしまう…\nそれだけはあってはなりません\nあなた方も、わかっていますわね？", 3, 105);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (0.0, "エリコ", 10142, 6, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 106, "2030/12/17 14:59:59", "まずまずの結果ではありますが、\nこの程度で満足してもらっては\n困りますわ。エリコ班の一員として、\nより高みを目指していただきますので", 6, 106);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (10.6, "エリコ", 10142, 3, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 107, "2030/12/17 14:59:59", "私の指導を受けながら、この結果は…\nもっと真剣に考えねばなりませんね\nあなた方が怠けずにいるには、\nどんなしつけが必要かを…クスクス", 8, 107);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (7.54, "エリコ", 10142, 6, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 108, "2030/12/17 14:59:59", "ひとまず訓練をこなしたご褒美か、\n実力を出しきれたとは言えない罰か…\nみなさんにどちらを与えるべきか\n少し悩む結果ですわね", 4, 108);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (11.5, "エリコ", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 109, "2030/12/17 14:59:59", "なかなかいい戦いぶりでしたわ\nこれもあなた方の頑張りと、何より\n優秀な教官である私の教育の賜物\nそうですわね？　クスクスクス…", 7, 109);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (8.83, "エリコ", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 110, "2030/12/17 14:59:59", "これだけ進めたのならば合格点ですわ\nでも、もっと高みを目指したいと\n思っているのなら…さらなる訓練にも\n付き合って差し上げましょう", 1, 110);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (6.68, "エリコ", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 111, "2030/12/17 14:59:59", "未熟で頼りなかったあなた方が、\n見違えるように成長しました\nなるほど…これこそが、教官冥利に\n尽きるという気持ちなのですね", 2, 111);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (8.8, "エリコ", 10142, 6, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 112, "2030/12/17 14:59:59", "まさかあなた方が、私の予想すら\n超える力を発揮するとは…驚きました\nもはやゴミ虫などではありません\n一人前の騎士として胸を張りなさい", 2, 112);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (8.9, "エリコ", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 113, "2030/12/17 14:59:59", "クスクス、見事な働きです\nみなさんならできると信じていました\n他でもない私の指導を受けた、\nエリコ班の優秀な新兵なのですから", 1, 113);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (3.7, "エリコ", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129901, 114, "2030/12/17 14:59:59", "なんてすばらしい成績…！\n今日という日は『あのおかたを想い\nエリコが限界を超えた記念日』として\n歴史に刻まれることでしょう…！", 5, 114);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (7.6, "マコト", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 200, "2030/12/17 14:59:59", "よし、いい訓練になったな\nおまえたちもよく動けてたし、\nちゃんと成長できてると思うぜ\nその調子で頑張れよっ", 2, 200);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (2.25, "マコト", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 201, "2030/12/17 14:59:59", "ひとまずゴールおめでとう！\nでも、努力は継続してこそだからな\nおまえたちにやる気があるなら、\n何度だって付き合ってやるよ", 1, 201);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (3.28, "マコト", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 202, "2030/12/17 14:59:59", "行軍訓練はこれにて完了！\n…なーんて思ってないよな？\n学んだことが体に染みつくまで\n地道に繰り返すのが練習ってもんさ", 1, 202);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (2.98, "マコト", 10142, 4, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 203, "2030/12/17 14:59:59", "みんなに無理をさせちまったか…\nでもこれで諦めることはないぜ\n次はきっとうまくいく。そう信じて\n鍛え続ければ、道は開けるはずだ！", 1, 203);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (3.0, "マコト", 10142, 4, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 204, "2030/12/17 14:59:59", "こいつは悔しい結果だな…\nま、反省点はいろいろあったし\nひとつずつ乗り越えていこう\nあたしたちで力を合わせて、なっ！", 1, 204);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (10.3, "マコト", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 205, "2030/12/17 14:59:59", "おまえたちはまだ未熟な訓練兵、\n失敗を必要以上に悔やむことはねえよ\nでも実戦じゃこうはいかないからな\n次は気合を入れ直していけよっ！", 2, 205);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (2.93, "マコト", 10142, 6, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 206, "2030/12/17 14:59:59", "これがおまえたちの全力？\nいやいや、そんなはずはないよなっ\nおまえらならもっと強くなれる！\nあたしが言うんだ、間違いないぜ！", 1, 206);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (9.3, "マコト", 10142, 3, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 207, "2030/12/17 14:59:59", "おまえたちの実力を考えりゃ、\nベストを尽くせたとは言えない成績だ\nなら、次やるべきことも決まってる\n気持ちを切り替えて、鍛え直すんだ！", 1, 207);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (6.9, "マコト", 10142, 4, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 208, "2030/12/17 14:59:59", "まだまだ課題がある内容だったな～\n無駄な動き、判断の遅れ…\nそういうのをしっかり直していけば、\n記録ももっと伸びるはずだっ", 1, 208);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (0.0, "マコト", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 209, "2030/12/17 14:59:59", "ここまでいけりゃ、合格点！\nむしろ、最初の頼りなさを思えば\nすげえ成長してるんじゃねえか？\n胸を張れる結果だと思うぜっ！", 2, 209);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (5.95, "マコト", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 210, "2030/12/17 14:59:59", "なかなかハードな訓練だったけど、\nみんなしっかりついてこられたな\n地道に続けた基礎トレの成果が\n形になってる、その証だぜっ", 2, 210);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (6.73, "マコト", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 211, "2030/12/17 14:59:59", "今回の訓練もよく頑張ったな！\nしっかり休んで次に備えろよ！\nなんつーか、教え子が成長してくのを\n見るのは楽しいもんだな…", 1, 211);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (0.0, "マコト", 10142, 2, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 212, "2030/12/17 14:59:59", "おまえら、すげえじゃねえか！\nこれならもう、ひよっこ新兵なんて\n言えねえな。きっと騎士団でも\n大活躍間違いなしだぜ！", 2, 212);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (6.65, "マコト", 10142, 1, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 213, "2030/12/17 14:59:59", "敵との戦い方、状況判断の正確さ\n何より根性…どれも最高だったぞ！\nうかうかしてたら、教官のあたしまで\n追い抜かれちまうかもな…へへっ", 2, 213);
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (3.05, "マコト", 10142, 6, "2024/03/31 12:00:00", 0.0, 24, 0.0, 129801, 214, "2030/12/17 14:59:59", "あたしの指導が良かった？\nいやいや、ここまで強くなれたのは、\n他でもないおまえたち自身が努力した\nおかげだよ。改めて…おめでとうっ！", 1, 214);
